namespace Toarnbeike.Unions.SourceGenerator.Emitters.Rendering;

internal static class AutoGeneratedMessage
{
    public static string Create(string union, string emitterName)
    {
        return $"""
                 # nullable enable

                 // <auto-generated>
                 //   This file was auto generated for the {union} Union.
                 //   Generator: {emitterName}
                 //   Created: {DateTime.UtcNow:u}
                 //   This is an auto-generated file. Do not modify.
                 // </auto-generated>
                 """;
    }
}
